mapper.select:
SELECT n.id, n.title, CASE WHEN LENGTH(n.content) > 100 THEN CONCAT(LEFT(n.content, 100), '...') ELSE n.content END AS content, n.publisher_id, n.is_top, n.status, n.create_time, n.update_time, u.real_name AS publisherName FROM ntc_notice n LEFT JOIN sys_user u ON n.publisher_id = u.id WHERE n.status = 1
AND (n.title LIKE CONCAT('%', #{keyword}, '%') OR n.content LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY n.is_top DESC, n.create_time DESC LIMIT #{offset}, #{limit}
